void applySeasonalPricing(Order order, LocalDate orderDate) {
    if (isInSummerSeason(orderDate) && qualifiesForSeasonalDiscount(order)) {
        order.applyDiscountRate(SUMMER_SEASONAL_DISCOUNT_RATE);
    }
}

private boolean isInSummerSeason(LocalDate date) {
    return !date.isBefore(SUMMER_SEASON_START) && !date.isAfter(SUMMER_SEASON_END);
}

private boolean qualifiesForSeasonalDiscount(Order order) {
    return order.calculateTotal().isGreaterThan(SEASONAL_DISCOUNT_MINIMUM_ORDER_VALUE);
}
